import React, { useState } from 'react';

export default function Controls({ onInsert, onExtractMin, onDecreaseKey, onDelete, onUnion, onClear }) {
  const [insertKey, setInsertKey] = useState('');
  const [decreaseId, setDecreaseId] = useState('');
  const [decreaseKey, setDecreaseKey] = useState('');
  const [deleteId, setDeleteId] = useState('');

  return (
    <div style={styles.container}>
      <div style={styles.section}>
        <input
          type="number"
          value={insertKey}
          onChange={(e) => setInsertKey(e.target.value)}
          placeholder="Key to insert"
          style={styles.input}
        />
        <button 
          onClick={() => {
            if (insertKey) {
              onInsert(Number(insertKey));
              setInsertKey('');
            }
          }}
          style={styles.button}
        >
          Insert
        </button>
      </div>

      <div style={styles.section}>
        <button onClick={onExtractMin} style={styles.button}>
          Extract Min
        </button>
      </div>

      <div style={styles.section}>
        <input
          type="number"
          value={decreaseId}
          onChange={(e) => setDecreaseId(e.target.value)}
          placeholder="Node ID"
          style={styles.input}
        />
        <input
          type="number"
          value={decreaseKey}
          onChange={(e) => setDecreaseKey(e.target.value)}
          placeholder="New Key"
          style={styles.input}
        />
        <button
          onClick={() => {
            if (decreaseId && decreaseKey) {
              onDecreaseKey(Number(decreaseId), Number(decreaseKey));
              setDecreaseId('');
              setDecreaseKey('');
            }
          }}
          style={styles.button}
        >
          Decrease Key
        </button>
      </div>

      <div style={styles.section}>
        <input
          type="number"
          value={deleteId}
          onChange={(e) => setDeleteId(e.target.value)}
          placeholder="Node ID to delete"
          style={styles.input}
        />
        <button
          onClick={() => {
            if (deleteId) {
              onDelete(Number(deleteId));
              setDeleteId('');
            }
          }}
          style={styles.button}
        >
          Delete Node
        </button>
      </div>

      <div style={styles.section}>
        <button onClick={onClear} style={styles.button}>
          Clear Heap
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    gap: '10px',
    padding: '15px',
    backgroundColor: '#f5f5f5',
    borderRadius: '8px',
  },
  section: {
    display: 'flex',
    gap: '8px',
    alignItems: 'center',
  },
  input: {
    padding: '8px',
    borderRadius: '4px',
    border: '1px solid #ddd',
  },
  button: {
    padding: '8px 16px',
    borderRadius: '4px',
    border: 'none',
    backgroundColor: '#2196f3',
    color: 'white',
    cursor: 'pointer',
  }
};
